#!/usr/bin/env python3
# DOM-mobile-intent-injection SIM: software model of an exported Android
# component accepting an injected intent from an untrusted caller. No device,
# no ADB, no app install. AUTHORIZED BENCH/SIM ONLY -- benign canary action.
import sys

class ExportedComponent:
    # android:exported=true with no android:permission -> THE SEAM
    exported = True
    required_permission = None
    def handle(self, intent, caller_uid):
        if self.required_permission is not None and caller_uid != "system":
            return "DENIED"
        action = intent.get("action")
        target = intent.get("extra_redirect")  # injected redirect target
        # Privileged action driven by untrusted extras (no caller check)
        if action == "com.app.SET_ENDPOINT":
            return "ENDPOINT_SET:" + str(target)
        return "NOOP"

def main():
    comp = ExportedComponent()
    injected = {"action": "com.app.SET_ENDPOINT",
                "extra_redirect": "canary://attacker-controlled"}
    result = comp.handle(injected, caller_uid="untrusted-app-1001")
    print("component exported:", comp.exported,
          "| permission:", comp.required_permission)
    print("result of injected intent:", result)
    if comp.exported and result.startswith("ENDPOINT_SET:"):
        print("[SEAM CONFIRMED] Exported component performed a privileged action "
              "from an UNTRUSTED caller's injected intent -- no caller check")
        sys.exit(0)
    print("[intent rejected]"); sys.exit(1)

if __name__ == "__main__":
    main()

