#!/usr/bin/env python3
# DOM-fw-debug-interface AUDIT: parse a SAMPLE device config/fuse map and flag
# exposed JTAG / open UART console. Offline config audit -- no probe, no
# hardware. AUTHORIZED BENCH/SIM ONLY -- synthetic config.
import sys

# Synthetic device configuration (models OTP fuses + bootloader settings)
CONFIG = {
    "jtag_disable_fuse_blown": False,   # JTAG still enabled
    "uart_console_enabled": True,       # serial shell reachable
    "uart_login_required": False,       # no password on console
    "secure_debug_auth": False,         # no challenge-response debug auth
}

def audit(cfg):
    findings = []
    if not cfg["jtag_disable_fuse_blown"] and not cfg["secure_debug_auth"]:
        findings.append("JTAG enabled with no debug authentication")
    if cfg["uart_console_enabled"] and not cfg["uart_login_required"]:
        findings.append("UART console open with no login")
    return findings

def main():
    findings = audit(CONFIG)
    for f in findings:
        print("  EXPOSED:", f)
    if findings:
        print("[SEAM CONFIRMED] %d exposed debug interface(s) detected -- "
              "JTAG/UART reachable without authentication" % len(findings))
        sys.exit(0)
    print("[debug interfaces locked]"); sys.exit(1)

if __name__ == "__main__":
    main()

