#!/usr/bin/env python3
# DOM-rogue-ap-eviltwin DETECT: receive-only analysis of a SYNTHETIC beacon
# capture to flag an evil-twin / rogue AP. No radio, no monitor mode, no
# transmit. AUTHORIZED BENCH/SIM ONLY -- synthetic records.
import sys

# Synthetic 'observed' beacons (as if parsed from a recorded capture file)
BEACONS = [
    {"ssid": "CorpWiFi", "bssid": "AA:BB:CC:00:00:01", "ch": 6,  "sec": "WPA2"},
    {"ssid": "CorpWiFi", "bssid": "DE:AD:BE:EF:00:99", "ch": 11, "sec": "OPEN"},
]
# Known-good authorized BSSIDs for the corporate SSID (allowlist)
AUTHORIZED = {"CorpWiFi": {"AA:BB:CC:00:00:01"}}

def detect(beacons):
    findings = []
    for b in beacons:
        allowed = AUTHORIZED.get(b["ssid"], set())
        if allowed and b["bssid"] not in allowed:
            why = "unknown BSSID"
            if b["sec"] == "OPEN":
                why += " + security downgraded to OPEN"
            findings.append((b["ssid"], b["bssid"], why))
    return findings

def main():
    findings = detect(BEACONS)
    for ssid, bssid, why in findings:
        print("  ROGUE AP:", ssid, "@", bssid, "->", why)
    if findings:
        print("[SEAM CONFIRMED] Evil-twin detected -- authorized SSID advertised "
              "by an unauthorized BSSID (and/or open security) to lure clients")
        sys.exit(0)
    print("[no rogue AP]"); sys.exit(1)

if __name__ == "__main__":
    main()
